// Download and parse the GOV.UK sponsor CSV
// Filter for Skilled Worker route sponsors only
const csvUrl = 'https://assets.publishing.service.gov.uk/media/69b3d0b1c8010d37b34e0111/2026-03-13_-_Worker_and_Temporary_Worker.csv';

try {
  const response = await fetch(csvUrl);
  const csvText = await response.text();
  const lines = csvText.split('\n');
  const headers = lines[0].split(',').map(h => h.trim().replace(/"/g, ''));

  // Parse all sponsors
  const allSponsors = [];
  for (let i = 1; i < lines.length; i++) {
    if (!lines[i].trim()) continue;
    // Handle CSV with possible quoted fields
    const cols = lines[i].match(/("[^"]*"|[^,]*)/g) || [];
    const clean = cols.map(c => c.replace(/^"|"$/g, '').trim());

    const name = clean[0] || '';
    const town = clean[1] || '';
    const county = clean[2] || '';
    const typeRating = clean[3] || '';
    const route = clean[4] || '';

    // Only include Skilled Worker route
    if (!route.toLowerCase().includes('skilled worker')) continue;

    allSponsors.push({ name, town, county, typeRating, route });
  }

  // Randomly sample 50 sponsors to check via Apollo
  // (API rate limits mean we can't check all 120K+)
  const shuffled = allSponsors.sort(() => Math.random() - 0.5);
  const sample = shuffled.slice(0, 50);

  return sample.map(s => ({ json: s }));
} catch (error) {
  return [{ json: { error: error.message, sponsors: [] } }];
}

// Check if Apollo found the company and it has ≤100 employees
const item = $input.first().json;
const sponsorName = $('Loop Over Sponsors').item.json.name;
const sponsorTown = $('Loop Over Sponsors').item.json.town;

const accounts = item.accounts || [];
if (accounts.length === 0) {
  return [{ json: { skip: true, reason: 'not_found', company: sponsorName } }];
}

const org = accounts[0];
const orgId = org.organization_id || org.id;
const domain = org.domain || '';
const name = org.name || sponsorName;

// We'll need to enrich to get employee count
return [{ json: { 
  skip: false,
  orgId,
  domain,
  name,
  sponsorName,
  sponsorTown,
  industry: org.industry || 'Unknown'
} }];

// Filter: only keep companies with ≤100 employees
const item = $input.first().json;
const prev = $('Check Org Found').item.json;
const org = item.organization || {};

const empCount = org.estimated_num_employees || 999;
if (empCount > 100) {
  return [{ json: { skip: true, reason: 'too_large', company: prev.name, employees: empCount } }];
}

return [{ json: {
  skip: false,
  orgId: prev.orgId || org.id,
  name: org.name || prev.name,
  sponsorName: prev.sponsorName,
  sponsorTown: prev.sponsorTown,
  domain: org.primary_domain || prev.domain,
  employees: empCount,
  industry: org.industry || prev.industry || 'Unknown',
  description: (org.short_description || '').substring(0, 500),
  linkedinUrl: org.linkedin_url || '',
  websiteUrl: org.website_url || '',
  foundedYear: org.founded_year || null,
  city: org.city || prev.sponsorTown || 'United Kingdom',
  country: org.country || 'United Kingdom'
} }];

// Combine org data with job postings
const item = $input.first().json;
const org = $('Filter ≤100 Employees').item.json;
const postings = item.organization_job_postings || [];

if (postings.length === 0) {
  // No active job postings - still include the company with a generic role
  return [{ json: {
    company: org.name,
    sponsorName: org.sponsorName,
    location: org.city || 'United Kingdom',
    employeeCount: org.employees,
    industry: org.industry,
    description: org.description,
    linkedinUrl: org.linkedinUrl,
    websiteUrl: org.websiteUrl,
    hasJobPostings: false,
    jobs: [{
      title: 'Open to Applications',
      location: org.city || 'United Kingdom',
      url: org.websiteUrl || org.linkedinUrl || '',
      salaryMin: 25000,
      salaryMax: 40000
    }]
  } }];
}

// Filter for UK-based jobs only, take top 3
const ukJobs = postings
  .filter(p => {
    const loc = (p.city || p.location || '').toLowerCase();
    const country = (p.country || '').toLowerCase();
    return country.includes('united kingdom') || country.includes('uk') || 
           loc.includes('london') || loc.includes('manchester') || 
           loc.includes('birmingham') || loc.includes('edinburgh') ||
           loc.includes('bristol') || loc.includes('leeds') || loc.includes('cambridge');
  })
  .slice(0, 3);

if (ukJobs.length === 0 && postings.length > 0) {
  // Use first posting regardless of location
  ukJobs.push(postings[0]);
}

const jobsList = ukJobs.map(p => ({
  title: p.title || 'Open Role',
  location: p.city || org.city || 'United Kingdom',
  url: p.url || '',
  salaryMin: 25000,
  salaryMax: 40000
}));

return [{ json: {
  company: org.name,
  sponsorName: org.sponsorName,
  location: org.city || 'United Kingdom',
  employeeCount: org.employees,
  industry: org.industry,
  description: org.description,
  linkedinUrl: org.linkedinUrl,
  websiteUrl: org.websiteUrl,
  hasJobPostings: true,
  jobs: jobsList
} }];

