// Build final job objects to push to MicroSponsor webhook
const orgData = $('Combine Org + Jobs').item.json;
const aiDescription = $input.first().json.output?.[0]?.content?.[0]?.text || $input.first().json.text || orgData.description || '';

const results = [];
for (const job of orgData.jobs) {
  results.push({
    json: {
      company: orgData.company,
      jobTitle: job.title,
      location: job.location || orgData.location || 'United Kingdom',
      employeeCount: orgData.employeeCount,
      salaryMin: job.salaryMin || 25000,
      salaryMax: job.salaryMax || 40000,
      isNewEntrantFriendly: true,
      companyDescription: aiDescription,
      industry: orgData.industry || 'Technology',
      linkedinUrl: job.url || orgData.linkedinUrl || '',
      companyLinkedinUrl: orgData.linkedinUrl || '',
      hiringManager: 'Hiring Manager',
      hiringManagerEmail: '',
      postedDays: 0
    }
  });
}

return results;

// Return summary of the refresh operation
const webhookResult = $input.first().json;
return [{ json: {
  success: true,
  message: 'Refresh complete',
  results: webhookResult.results || { inserted: 0, updated: 0, verified: 0 },
  timestamp: new Date().toISOString()
} }];
